import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { PlusCircle, Store, ArrowLeft, MapPin, Trash2 } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

// Corrección para el icono de Leaflet que a veces desaparece en React
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const DashboardVendedor = () => {
  const { user } = useAuth();
  const [locales, setLocales] = useState([]);
  const [localActivo, setLocalActivo] = useState(null);
  const [mostrarFormLocal, setMostrarFormLocal] = useState(false);
  const [loading, setLoading] = useState(true);

  // Estado del nuevo local con geolocalización por defecto (Tucumán como ejemplo)
  const [nuevoLocal, setNuevoLocal] = useState({
    nombre: '',
    direccion: '',
    lng: -65.2176,
    lat: -26.8161
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { if (user) fetchLocales(); }, [user]);

  const fetchLocales = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/locales/vendedor/${user.id || user._id}`);
      setLocales(res.data);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  // Componente interno para capturar el click en el mapa
  const LocationMarker = () => {
    useMapEvents({
      click(e) {
        setNuevoLocal({ ...nuevoLocal, lat: e.latlng.lat, lng: e.latlng.lng });
      },
    });
    return <Marker position={[nuevoLocal.lat, nuevoLocal.lng]} />;
  };

  const handleCrearLocal = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(`${API_URL}/api/locales`, {
        ...nuevoLocal,
        vendedorId: user.id || user._id
      });
      setLocales([...locales, res.data]);
      setLocalActivo(res.data);
      setMostrarFormLocal(false);
    } catch (err) { alert("Error al guardar local"); }
  };

  if (loading) return <div style={{textAlign:'center', padding:'50px'}}>Cargando...</div>;

  if (!localActivo) {
    return (
      <div style={containerStyle}>
        <div style={headerStyle}>
          <h2>Mis Locales</h2>
          <button onClick={() => setMostrarFormLocal(!mostrarFormLocal)} style={btnPrimary}>
            {mostrarFormLocal ? 'Cancelar' : <><PlusCircle size={18}/> Nuevo Local</>}
          </button>
        </div>

        {mostrarFormLocal ? (
          <div style={formCard}>
            <div style={formLayout}>
              {/* Lado Izquierdo: Datos */}
              <form onSubmit={handleCrearLocal} style={inputsContainer}>
                <h3 style={{margin:0}}>Datos del Local</h3>
                <input style={inputS} placeholder="Nombre del comercio" onChange={e => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} required />
                <input style={inputS} placeholder="Dirección exacta" onChange={e => setNuevoLocal({...nuevoLocal, direccion: e.target.value})} required />
                <div style={coordsBadge}>
                  <MapPin size={14} /> {nuevoLocal.lat.toFixed(4)}, {nuevoLocal.lng.toFixed(4)}
                </div>
                <button type="submit" style={btnSubmit}>Guardar Local y Ubicación</button>
              </form>

              {/* Lado Derecho: Mapa */}
              <div style={mapWrapper}>
                <p style={mapHint}>Haz clic en el mapa para ubicar tu local:</p>
                <MapContainer center={[nuevoLocal.lat, nuevoLocal.lng]} zoom={13} style={{ height: '300px', borderRadius: '12px' }}>
                  <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
                  <LocationMarker />
                </MapContainer>
              </div>
            </div>
          </div>
        ) : (
          <div style={gridLocales}>
            {locales.map(l => (
              <div key={l._id} style={cardLocal} onClick={() => setLocalActivo(l)}>
                <Store size={40} color="#e67e22" />
                <h3 style={{margin:'10px 0 5px 0'}}>{l.nombre}</h3>
                <p style={{fontSize:'0.8rem', color:'#64748b'}}>{l.direccion}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  return (
    <div style={containerStyle}>
       <button onClick={() => setLocalActivo(null)} style={btnBack}><ArrowLeft size={18}/> Volver a mis locales</button>
       <h1 style={{marginTop:'10px'}}>{localActivo.nombre}</h1>
       <p>Aquí va el resto de tu gestión de pedidos y productos...</p>
    </div>
  );
};

// --- ESTILOS "CON VIDA" ---
const containerStyle = { padding: '30px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'Inter, sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const formCard = { background: 'white', padding: '25px', borderRadius: '24px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' };
const formLayout = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '30px' };
const inputsContainer = { display: 'flex', flexDirection: 'column', gap: '15px' };
const inputS = { padding: '12px', borderRadius: '12px', border: '1px solid #e2e8f0', fontSize: '1rem', outline: 'none' };
const mapWrapper = { display: 'flex', flexDirection: 'column', gap: '10px' };
const mapHint = { margin: 0, fontSize: '0.85rem', color: '#64748b', fontWeight: '500' };
const coordsBadge = { background: '#f1f5f9', padding: '8px 12px', borderRadius: '8px', fontSize: '0.8rem', color: '#475569', display: 'flex', alignItems: 'center', gap: '5px', alignSelf: 'start' };
const btnPrimary = { background: '#e67e22', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: '600' };
const btnSubmit = { background: '#1e293b', color: 'white', padding: '14px', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' };
const gridLocales = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' };
const cardLocal = { background: 'white', padding: '30px', borderRadius: '24px', border: '1px solid #e2e8f0', textAlign: 'center', cursor: 'pointer', transition: 'transform 0.2s', ':hover': { transform: 'translateY(-5px)' } };

export default DashboardVendedor;
